INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1364, 155603, 6, 248, '改变', '150天说长不长，说短也不短，但是它却足已让一个人改变。这次回来，老友们或多或少地感觉到我的变化。连他那种感觉慢半拍的人都直言不讳地告诉我：鱼，你变了，变得现实了。如果我说是因为生活所迫，环境所逼，兴许他也会相信。但是我不能欺骗我自己，因为我知道这一切与他有关。 
<br>  妈妈说：在同一个地方跌倒两次的人最笨了。于是，我小心翼翼地提醒着自己不要成为那个最笨的人。可是我不明白到底为什么，我越是担心的事情却越是会发生。 
<br>  一次聚会的偶遇，让我们又走在一起。之前的一切仍历历在目，曾经跌倒过，受过伤的人，也许岁月能抚平伤口，但留下的疤痕是永不退去的，便何况是感情上的伤。但是一旦爱情来敲门，谁也挡不了，顾不得那么多了。很快的，他又回到那个遥远的国度，我也开始忙于工作，读书... 
<br>  直到那150天漂泊异国他乡的日子，看着身边一对对分隔两地的恋人争吵，分手，看多了，就习惯了，也渐渐麻木了。偶尔也会想到我们虚无飘渺的未来，很痛苦，所以我选择逃避。一直到有一天，一群好友开起了我们的玩笑。虽然我嘴上说我们不会分手，但是心里却有种不安的情绪。接下来的日子，我开始认真思考着我们的爱情。随着时间的流逝，我对他的思念和他给我的e-mail成正比，越来越少了。当我在犹豫不决的时候，也有许多人劝我不要放手，毕竟这段感情来得不容易。可是，距离是我们之间最大的障碍，这是谁也无法改变的事实，我们在一起是不会有结果的。人总是要长大的，不能老是活在幻想中，不现实一点怎么能在这种社会里生存呢？于是，我决定了... 
<br>  记得张小娴曾说过，无法厮守终生的爱情，不过是人在长途旅程中，来去匆匆的转机站，无论停留多久，始终要离开，坐另一班机。嗯，我现在应该去寻找属于我的那班机。', '150天说长不长，说短也不短，但是它却足已让一个人改变。这次回来，老友们或多或少地感觉到我的变化。连他那种感觉慢半拍的人都直言不讳地告诉我：鱼，你变了，变得现实了。如果我说是因为生活所迫，环境所逼，兴许他也会相信。但是我不能欺骗我自己，因为我知道这一切与他有关。

妈妈说：在同一个地方跌倒两次的人最笨了。于是，我小心翼翼地提醒着自己不要成为那个最笨的人。可是我不明白到底为什么，我越是担心的事情却越是会发生。

一次聚会的偶遇，让我们又走在一起。之前的一切仍历历在目，曾经跌倒过，受过伤的人，也许岁月能抚平伤口，但留下的疤痕是永不退去的，便何况是感情上的伤。但是一旦爱情来敲门，谁也挡不了，顾不得那么多了。很快的，他又回到那个遥远的国度，我也开始忙于工作，读书...

直到那150天漂泊异国他乡的日子，看着身边一对对分隔两地的恋人争吵，分手，看多了，就习惯了，也渐渐麻木了。偶尔也会想到我们虚无飘渺的未来，很痛苦，所以我选择逃避。一直到有一天，一群好友开起了我们的玩笑。虽然我嘴上说我们不会分手，但是心里却有种不安的情绪。接下来的日子，我开始认真思考着我们的爱情。随着时间的流逝，我对他的思念和他给我的e-mail成正比，越来越少了。当我在犹豫不决的时候，也有许多人劝我不要放手，毕竟这段感情来得不容易。可是，距离是我们之间最大的障碍，这是谁也无法改变的事实，我们在一起是不会有结果的。人总是要长大的，不能老是活在幻想中，不现实一点怎么能在这种社会里生存呢？于是，我决定了...

记得张小娴曾说过，无法厮守终生的爱情，不过是人在长途旅程中，来去匆匆的转机站，无论停留多久，始终要离开，坐另一班机。嗯，我现在应该去寻找属于我的那班机。', '我像是咖啡豆，随时都有粉身的准备，亲爱的你，请将我磨碎 。我满溢的泪，会蒸馏出滚烫的水，再将我的思念溶解，化为少许糖味，盛装一杯咖啡，陪你度过，每个不眠的夜！', '2002-03-27 09:33:00', 11, '20030122185145_bbsid_155603_board_6_cdfa577d61.html', '20030122185145');
